cdef str _period_format_none(int64_t value, int freq):
    """
    Fast path for the default, locale-independent Period string format.

    This is equivalent to routing through _period_strftime with the default
    format string chosen for each frequency group, but avoids the relatively
    expensive strftime/locale/placeholder machinery for common scalar and
    array formatting paths.
