    cdef:
        int freq_group = get_freq_group(freq)
        int64_t ordinal
        int year, month, quarter
        int32_t us, ps
        npy_datetimestruct dts
        int64_t left, right

    if freq_group == FR_ANN:
        # Annual ordinals are years relative to 1970.  The display year is
        # the fiscal year, matching the default "%Y" strftime path.
        year = <int>(value + 1970)
        return f"{year:04d}"

    elif freq_group == FR_QTR:
        get_date_info(value, freq, &dts)
        quarter = get_yq(value, freq, &dts)
        return f"{dts.year:04d}Q{quarter}"

    elif freq_group == FR_MTH:
        # Monthly ordinals are months relative to 1970-01.
        ordinal = value + 1970 * 12
        year = <int>(ordinal // 12)
        month = <int>(ordinal % 12) + 1
        return f"{year:04d}-{month:02d}"

    elif freq_group == FR_WK:
        left = period_asfreq(value, freq, FR_DAY, 0)
        right = period_asfreq(value, freq, FR_DAY, 1)
